<?php declare(strict_types=1); ?>
<div class="wrap edis-admin"><h1><?php echo esc_html__('Source Evidence Coverage','edis-evidence-exporter'); ?></h1><p class="edis-lead"><?php echo esc_html__('Coverage is not a UX score. It tells Python which source evidence exists, is partial, is unavailable, or could not be collected.','edis-evidence-exporter'); ?></p>
