<?php if(is_array($latestJob)): ?><section class="edis-panel"><h2><?php echo esc_html__('Latest job evidence states','edis-evidence-exporter'); ?></h2><div class="edis-two-columns"><div><h3><?php echo esc_html__('Source truth','edis-evidence-exporter'); ?></h3><pre><?php echo esc_html(wp_json_encode($latestJob['truth_summary']??[],JSON_PRETTY_PRINT|JSON_UNESCAPED_UNICODE)); ?></pre></div><div><h3><?php echo esc_html__('Source availability','edis-evidence-exporter'); ?></h3><pre><?php echo esc_html(wp_json_encode($latestJob['availability_summary']??[],JSON_PRETTY_PRINT|JSON_UNESCAPED_UNICODE)); ?></pre></div></div></section><?php endif; ?>
<section class="edis-panel"><h2><?php echo esc_html__('How to read the states','edis-evidence-exporter'); ?></h2><dl class="edis-definition-list"><dt>VERIFIED</dt><dd><?php echo esc_html__('The source contract and retrieval path are verified. This does not mean the design is good.','edis-evidence-exporter'); ?></dd><dt>PARTIAL</dt><dd><?php echo esc_html__('Valid source evidence exists, but exact semantics remain version- or fixture-bounded.','edis-evidence-exporter'); ?></dd><dt>UNKNOWN</dt><dd><?php echo esc_html__('The source contract cannot be identified safely.','edis-evidence-exporter'); ?></dd><dt>UNSUPPORTED</dt><dd><?php echo esc_html__('The source contract is explicitly unsupported. Version 3.4 no longer mislabels missing index builders as unsupported Elementor collectors.','edis-evidence-exporter'); ?></dd></dl></section></div>
